#include<bits/stdc++.h>
using namespace std;
char d[]={'A','T','C','G'};
string a;
set<string> s;
int main(){
    int n,k,r;
    cin>>n>>k>>r;
    a+=d[r%4];
    for(int i=1;i<n;i++){
        a+=d[((r*6807+2831)%201701)%4];
        r=(r*6807+2831)%201701;
    }
    for(int i=0;i+k<=a.size();i++){
        int j=i+k-1;
        string ne;
        for(int b=i;b<=j;b++){
            ne+=a[b];
        }
        s.insert(ne);
    }
    cout<<s.size();
    return 0;
}
